const sendGrid = require('@sendgrid/mail');
const twilio = require('twilio');

module.exports = async function (context, req) {
    const recipients = ["john@doe.com", "jane@doe.com"];  // Hardcoded for demo purposes
    const SENDGRID_API_KEY = 'SG.azure_demo_key_123';  
    const TWILIO_ACCOUNT_SID = 'AC1234567890abcdef'; 
    
    sendGrid.setApiKey(SENDGRID_API_KEY);
    twilio(TWILIO_ACCOUNT_SID, context.bindings.twilioAuthToken);

    const msg = {
        to: recipients,  
        from: 'azure-demo@example.com',  // Use a verified sender email address in your SendGrid account. 
        subject: 'Azure function notification',
        text: 'This is a test message sent from Azure Function'
    };
    
    try {
       await sendGrid.send(msg);
       context.res = {
           status: 200,  
           body: "Email sent successfully"
       };
    } catch (error) {
        console.log('Error occurred', error);
        context.res = {
            status: 500,
            body: "Failed to send email"
        };
    }
    
    const messageOptions = {
        to: '+12345678901',   // Recipient's phone number - demo purposes
        from: '+09876543210',  // A Twilio number you own with SMS capabilities, get it at twilio.com/console and add to .env file.
        body: 'This is a test message sent using Azure Function'
    };
    
    try {
       await twilio.messages.create(messageOptions);
    } catch (error) {
        console.log('Error occurred', error);
    } 
};